import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Import Halaman
import Katalog from './pages/Katalog';
import DetailProduk from './pages/DetailProduk';
import Keranjang from './pages/Keranjang';
import Login from './pages/Login';
import DashboardAdmin from './pages/DashboardAdmin';

function App() {
  // State global untuk memantau apakah pengguna sudah login atau belum
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  return (
    <Router>
      <Routes>
        {/* Rute Publik: Katalog Utama */}
        <Route path="/" element={<Katalog isLoggedIn={isLoggedIn} />} />

        {/* Rute Detail Produk */}
        <Route path="/produk/:id" element={<DetailProduk />} />

        {/* Rute Login: Mengirim fungsi setIsLoggedIn untuk mengubah status saat berhasil masuk */}
        <Route 
          path="/login" 
          element={<Login setIsLoggedIn={setIsLoggedIn} />} 
        />

        {/* Rute Keranjang: Hanya bisa diakses jika sudah login (pelanggan) */}
        <Route 
          path="/keranjang" 
          element={isLoggedIn ? <Keranjang /> : <Navigate replace to="/login" />} 
        />

        {/* Rute Dashboard Admin: Mengirim fungsi setIsLoggedIn untuk proses logout */}
        <Route 
          path="/admin" 
          element={isLoggedIn ? <DashboardAdmin setIsLoggedIn={setIsLoggedIn} /> : <Navigate replace to="/login" />} 
        />

        {/* Alihkan rute yang tidak dikenal ke halaman utama */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default App;
